arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// ── Data schemas ────────────────────────────────────────────────────────────
// Input row matching the CSV columns.

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");

// Load CSV
IDataView allData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Build training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerData.Churned),
        featureColumnName: "Features"));

// Train / evaluate with a train-test split
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2, seed: 42);
var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(
    predictions, labelColumnName: nameof(CustomerData.Churned));

Console.WriteLine("===== Churn Model Metrics =====");
Console.WriteLine($"Accuracy : {metrics.Accuracy:P2}");
Console.WriteLine($"AUC      : {metrics.AreaUnderRocCurve:P2}");
Console.WriteLine($"F1 Score : {metrics.F1Score:P2}");

// Retrain on all data for production use
var fullModel = pipeline.Fit(allData);

// Create a reusable prediction engine
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(fullModel);

// ── Endpoints ───────────────────────────────────────────────────────────────

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

app.MapGet("/metrics", () => new
{
    metrics.Accuracy,
    metrics.AreaUnderRocCurve,
    metrics.F1Score,
    metrics.PositiveRecall,
    metrics.PositivePrecision
});

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var result = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Confidence = result.Probability
    });
});

app.Run();

// ── Types ───────────────────────────────────────────────────────────────────

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

